     1→<?php
     2→/**
     3→ * Plugin Name: AdminPulse
     4→ * Plugin URI: https://example.com/adminpulse
     5→ * Description: A lightweight dashboard widget that surfaces WordPress Site Health issues at a glance.
     6→ * Version: 1.0.0
     7→ * Requires at least: 6.2
     8→ * Requires PHP: 8.0
     9→ * Author: AdminPulse Team
    10→ * License: GPL-2.0+
    11→ * License URI: https://www.gnu.org/licenses/gpl-2.0.html
    12→ * Text Domain: adminpulse
    13→ *
    14→ * @package AdminPulse
    15→ */
    16→
    17→// Exit if accessed directly.
    18→if ( ! defined( 'ABSPATH' ) ) {
    19→	exit;
    20→}
    21→
    22→// Define plugin constants.
    23→define( 'ADMINPULSE_VERSION', '1.0.0' );
    24→define( 'ADMINPULSE_DIR', plugin_dir_path( __FILE__ ) );
    25→define( 'ADMINPULSE_URL', plugin_dir_url( __FILE__ ) );
    26→
    27→/**
    28→ * Get the transient key for caching health data.
    29→ * Includes blog ID for multisite isolation.
    30→ *
    31→ * @return string Transient key.
    32→ */
    33→function adminpulse_get_transient_key() {
    34→	$blog_id = get_current_blog_id();
    35→	return 'adminpulse_health_data_' . $blog_id;
    36→}
    37→
    38→/**
    39→ * Plugin activation hook.
    40→ * Performs version check and initializes transient.
    41→ */
    42→function adminpulse_activate() {
    43→	// Version check for PHP.
    44→	if ( version_compare( PHP_VERSION, '8.0', '<' ) ) {
    45→		deactivate_plugins( plugin_basename( __FILE__ ) );
    46→		wp_die(
    47→			esc_html__( 'AdminPulse requires PHP 8.0 or higher.', 'adminpulse' ),
    48→			'Plugin Activation Error',
    49→			array( 'back_link' => true )
    50→		);
    51→	}
    52→
    53→	// Version check for WordPress.
    54→	global $wp_version;
    55→	if ( version_compare( $wp_version, '6.2', '<' ) ) {
    56→		deactivate_plugins( plugin_basename( __FILE__ ) );
    57→		wp_die(
    58→			esc_html__( 'AdminPulse requires WordPress 6.2 or higher.', 'adminpulse' ),
    59→			'Plugin Activation Error',
    60→			array( 'back_link' => true )
    61→		);
    62→	}
    63→
    64→	// Initialize transient (will be populated on first widget load).
    65→	delete_transient( adminpulse_get_transient_key() );
    66→}
    67→register_activation_hook( __FILE__, 'adminpulse_activate' );
    68→
    69→/**
    70→ * Plugin deactivation hook.
    71→ * Cleans up transients.
    72→ */
    73→function adminpulse_deactivate() {
    74→	delete_transient( adminpulse_get_transient_key() );
    75→}
    76→register_deactivation_hook( __FILE__, 'adminpulse_deactivate' );
    77→
    78→/**
    79→ * Enqueue scripts and styles on dashboard pages only.
    80→ *
    81→ * @param string $hook_suffix The current admin page hook suffix.
    82→ */
    83→function adminpulse_enqueue_assets( $hook_suffix ) {
    84→	// Only load on dashboard page.
    85→	if ( 'index.php' !== $hook_suffix ) {
    86→		return;
    87→	}
    88→
    89→	// Don't load on Network Admin dashboard.
    90→	if ( is_network_admin() ) {
    91→		return;
    92→	}
    93→
    94→	// Enqueue CSS.
    95→	wp_enqueue_style(
    96→		'adminpulse-styles',
    97→		ADMINPULSE_URL . 'assets/css/adminpulse.css',
    98→		array(),
    99→		ADMINPULSE_VERSION
   100→	);
   101→
   102→	// Enqueue JavaScript with defer (in_footer = true).
   103→	wp_enqueue_script(
   104→		'adminpulse-script',
   105→		ADMINPULSE_URL . 'assets/js/adminpulse.js',
   106→		array(),
   107→		ADMINPULSE_VERSION,
   108→		true
   109→	);
   110→
   111→	// Localize script with nonce and AJAX URL.
   112→	wp_localize_script(
   113→		'adminpulse-script',
   114→		'adminpulseData',
   115→		array(
   116→			'ajaxUrl' => admin_url( 'admin-ajax.php' ),
   117→			'nonce'   => wp_create_nonce( 'adminpulse_nonce' ),
   118→		)
   119→	);
   120→}
   121→add_action( 'admin_enqueue_scripts', 'adminpulse_enqueue_assets' );
   122→
   123→/**
   124→ * Register the dashboard widget.
   125→ */
   126→function adminpulse_register_widget() {
   127→	// Don't register on Network Admin.
   128→	if ( is_network_admin() ) {
   129→		return;
   130→	}
   131→
   132→	// Check user capability.
   133→	if ( ! current_user_can( 'view_site_health_checks' ) && ! current_user_can( 'manage_options' ) ) {
   134→		return;
   135→	}
   136→
   137→	wp_add_dashboard_widget(
   138→		'adminpulse_health_widget',
   139→		__( 'Site Health', 'adminpulse' ),
   140→		'adminpulse_render_widget'
   141→	);
   142→}
   143→add_action( 'wp_dashboard_setup', 'adminpulse_register_widget' );
   144→
   145→/**
   146→ * Render the widget content with loading skeleton.
   147→ */
   148→function adminpulse_render_widget() {
   149→	?>
   150→	<div id="adminpulse-widget-content" class="adminpulse-widget">
   151→		<div class="adminpulse-loading">
   152→			<div class="adminpulse-skeleton adminpulse-skeleton-line"></div>
   153→			<div class="adminpulse-skeleton adminpulse-skeleton-line"></div>
   154→			<div class="adminpulse-skeleton adminpulse-skeleton-line"></div>
   155→		</div>
   156→	</div>
   157→	<div class="adminpulse-footer">
   158→		<button type="button" class="button adminpulse-refresh-btn" id="adminpulse-refresh">
   159→			<?php esc_html_e( 'Refresh', 'adminpulse' ); ?>
   160→		</button>
   161→	</div>
   162→	<?php
   163→}
