   165→/**
   166→ * Get health data from WP Site Health API.
   167→ *
   168→ * @param bool $force_refresh Whether to bypass cache.
   169→ * @return array Health data array.
   170→ */
   171→function adminpulse_get_health_data( $force_refresh = false ) {
   172→	$transient_key = adminpulse_get_transient_key();
   173→
   174→	// Check cache first (unless force refresh).
   175→	if ( ! $force_refresh ) {
   176→		$cached_data = get_transient( $transient_key );
   177→		if ( false !== $cached_data ) {
   178→			return $cached_data;
   179→		}
   180→	} else {
   181→		// Clear transient on manual refresh.
   182→		delete_transient( $transient_key );
   183→	}
   184→
   185→	// Load Site Health classes if not already loaded.
   186→	if ( ! class_exists( 'WP_Site_Health' ) ) {
   187→		require_once ABSPATH . 'wp-admin/includes/class-wp-site-health.php';
   188→	}
   189→
   190→	$site_health = WP_Site_Health::get_instance();
   191→	$health_data = array(
   192→		'issues'      => array(),
   193→		'total_count' => 0,
   194→		'error'       => false,
   195→	);
   196→
   197→	// Get direct tests.
   198→	$tests = WP_Site_Health::get_tests();
   199→
   200→	if ( empty( $tests ) || ! is_array( $tests ) ) {
   201→		$health_data['error'] = true;
   202→		return $health_data;
   203→	}
   204→
   205→	$issues = array();
   206→
   207→	// Run direct tests only (no external HTTP requests).
   208→	if ( ! empty( $tests['direct'] ) && is_array( $tests['direct'] ) ) {
   209→		foreach ( $tests['direct'] as $test_key => $test ) {
   210→			if ( ! is_callable( $test['test'] ) ) {
   211→				continue;
   212→			}
   213→
   214→			$result = call_user_func( $test['test'] );
   215→
   216→			if ( ! is_array( $result ) || empty( $result['status'] ) ) {
   217→				continue;
   218→			}
   219→
   220→			// Filter: only show issues (exclude 'good' status).
   221→			if ( 'good' === $result['status'] ) {
   222→				continue;
   223→			}
   224→
   225→			$issues[] = adminpulse_format_issue( $result, $test_key );
   226→		}
   227→	}
   228→
   229→	// Sort by severity: critical first, then recommended.
   230→	usort( $issues, 'adminpulse_sort_by_severity' );
   231→
   232→	$health_data['issues']      = $issues;
   233→	$health_data['total_count'] = count( $issues );
   234→
   235→	// Cache the result for 1 hour.
   236→	set_transient( $transient_key, $health_data, HOUR_IN_SECONDS );
   237→
   238→	return $health_data;
   239→}
   240→
   241→/**
   242→ * Format a health issue for display.
   243→ *
   244→ * @param array  $result   The test result.
   245→ * @param string $test_key The test identifier.
   246→ * @return array Formatted issue data.
   247→ */
   248→function adminpulse_format_issue( $result, $test_key ) {
   249→	$status = isset( $result['status'] ) ? $result['status'] : 'recommended';
   250→
   251→	// Map status to severity class.
   252→	$severity_class = 'adminpulse-warning';
   253→	$severity_label = __( 'Recommended', 'adminpulse' );
   254→
   255→	if ( 'critical' === $status ) {
   256→		$severity_class = 'adminpulse-critical';
   257→		$severity_label = __( 'Critical', 'adminpulse' );
   258→	}
   259→
   260→	// Transform technical messages to human-readable copy.
   261→	$label       = isset( $result['label'] ) ? $result['label'] : $test_key;
   262→	$description = isset( $result['description'] ) ? wp_strip_all_tags( $result['description'] ) : '';
   263→
   264→	// Get action links.
   265→	$actions = array();
   266→
   267→	if ( ! empty( $result['actions'] ) ) {
   268→		// Parse action links from HTML.
   269→		preg_match_all( '/<a[^>]+href=["\']([^"\']+)["\'][^>]*>([^<]+)<\/a>/i', $result['actions'], $matches, PREG_SET_ORDER );
   270→		foreach ( $matches as $match ) {
   271→			$actions[] = array(
   272→				'url'   => esc_url( $match[1] ),
   273→				'label' => sanitize_text_field( $match[2] ),
   274→			);
   275→		}
   276→	}
   277→
   278→	// Add relevant WordPress admin page links based on test type.
   279→	$admin_action = adminpulse_get_admin_action( $test_key );
   280→	if ( $admin_action && ! in_array( $admin_action['url'], array_column( $actions, 'url' ), true ) ) {
   281→		array_unshift( $actions, $admin_action );
   282→	}
   283→
   284→	return array(
   285→		'key'            => $test_key,
   286→		'label'          => adminpulse_humanize_label( $label ),
   287→		'description'    => adminpulse_humanize_description( $description ),
   288→		'status'         => $status,
   289→		'severity_class' => $severity_class,
   290→		'severity_label' => $severity_label,
   291→		'actions'        => $actions,
   292→	);
   293→}
   294→
   295→/**
   296→ * Get relevant admin page action for a test type.
   297→ *
   298→ * @param string $test_key The test identifier.
   299→ * @return array|null Action link data or null.
   300→ */
   301→function adminpulse_get_admin_action( $test_key ) {
   302→	$admin_pages = array(
   303→		'plugin_version'           => array(
   304→			'url'   => admin_url( 'plugins.php' ),
   305→			'label' => __( 'Update plugins', 'adminpulse' ),
   306→		),
   307→		'theme_version'            => array(
   308→			'url'   => admin_url( 'themes.php' ),
   309→			'label' => __( 'Update themes', 'adminpulse' ),
   310→		),
   311→		'wordpress_version'        => array(
   312→			'url'   => admin_url( 'update-core.php' ),
   313→			'label' => __( 'Update WordPress', 'adminpulse' ),
   314→		),
   315→		'php_version'              => array(
   316→			'url'   => 'https://wordpress.org/documentation/article/updating-php/',
   317→			'label' => __( 'Learn more', 'adminpulse' ),
   318→		),
   319→		'https_status'             => array(
   320→			'url'   => admin_url( 'options-general.php' ),
   321→			'label' => __( 'Site settings', 'adminpulse' ),
   322→		),
   323→		'ssl_support'              => array(
   324→			'url'   => 'https://wordpress.org/documentation/article/https-for-wordpress/',
   325→			'label' => __( 'Learn more', 'adminpulse' ),
   326→		),
   327→		'scheduled_events'         => array(
   328→			'url'   => admin_url( 'tools.php' ),
   329→			'label' => __( 'View tools', 'adminpulse' ),
   330→		),
   331→		'background_updates'       => array(
   332→			'url'   => admin_url( 'update-core.php' ),
   333→			'label' => __( 'Updates', 'adminpulse' ),
   334→		),
   335→		'autoloaded_options'       => array(
   336→			'url'   => 'https://developer.wordpress.org/reference/functions/get_option/',
   337→			'label' => __( 'Learn more', 'adminpulse' ),
   338→		),
   339→		'debug_enabled'            => array(
   340→			'url'   => 'https://wordpress.org/documentation/article/debugging-in-wordpress/',
   341→			'label' => __( 'Learn more', 'adminpulse' ),
   342→		),
   343→		'page_cache'               => array(
   344→			'url'   => admin_url( 'plugins.php' ),
   345→			'label' => __( 'View plugins', 'adminpulse' ),
   346→		),
   347→		'persistent_object_cache'  => array(
   348→			'url'   => 'https://developer.wordpress.org/reference/classes/wp_object_cache/',
   349→			'label' => __( 'Learn more', 'adminpulse' ),
   350→		),
   351→	);
   352→
   353→	if ( isset( $admin_pages[ $test_key ] ) ) {
   354→		$action = $admin_pages[ $test_key ];
   355→		// Ensure admin URLs are properly generated.
   356→		if ( strpos( $action['url'], 'http' ) !== 0 ) {
   357→			$action['url'] = esc_url( $action['url'] );
   358→		} else {
   359→			$action['url'] = esc_url( $action['url'] );
   360→		}
   361→		return $action;
   362→	}
   363→
   364→	// Default: link to Site Health page.
   365→	return array(
   366→		'url'   => esc_url( admin_url( 'site-health.php' ) ),
   367→		'label' => __( 'View Site Health', 'adminpulse' ),
   368→	);
   369→}
   370→
   371→/**
   372→ * Transform technical labels to human-readable copy.
   373→ *
   374→ * @param string $label The original label.
   375→ * @return string Human-readable label.
   376→ */
   377→function adminpulse_humanize_label( $label ) {
   378→	// Keep label readable but don't over-transform WordPress's already-good labels.
   379→	return sanitize_text_field( $label );
   380→}
   381→
   382→/**
   383→ * Transform technical descriptions to human-readable copy.
   384→ *
   385→ * @param string $description The original description.
   386→ * @return string Human-readable description.
   387→ */
   388→function adminpulse_humanize_description( $description ) {
   389→	// Truncate long descriptions for widget display.
   390→	$max_length = 150;
   391→	if ( strlen( $description ) > $max_length ) {
   392→		$description = substr( $description, 0, $max_length ) . '...';
   393→	}
   394→	return sanitize_text_field( $description );
   395→}
   396→
   397→/**
   398→ * Sort issues by severity (critical first, then recommended).
   399→ *
   400→ * @param array $a First issue.
   401→ * @param array $b Second issue.
   402→ * @return int Sort order.
   403→ */
   404→function adminpulse_sort_by_severity( $a, $b ) {
   405→	$severity_order = array(
   406→		'critical'    => 0,
   407→		'recommended' => 1,
   408→	);
   409→
   410→	$a_order = isset( $severity_order[ $a['status'] ] ) ? $severity_order[ $a['status'] ] : 2;
   411→	$b_order = isset( $severity_order[ $b['status'] ] ) ? $severity_order[ $b['status'] ] : 2;
   412→
   413→	return $a_order - $b_order;
   414→}
