   416→/**
   417→ * AJAX handler for getting health data.
   418→ */
   419→function adminpulse_ajax_get_health() {
   420→	// Verify nonce.
   421→	if ( ! check_ajax_referer( 'adminpulse_nonce', 'nonce', false ) ) {
   422→		wp_send_json_error(
   423→			array( 'message' => __( 'Security check failed.', 'adminpulse' ) ),
   424→			403
   425→		);
   426→	}
   427→
   428→	// Check user capability.
   429→	if ( ! current_user_can( 'view_site_health_checks' ) && ! current_user_can( 'manage_options' ) ) {
   430→		wp_send_json_error(
   431→			array( 'message' => __( 'You do not have permission to view site health.', 'adminpulse' ) ),
   432→			403
   433→		);
   434→	}
   435→
   436→	// Check if this is a force refresh request.
   437→	$force_refresh = isset( $_POST['refresh'] ) && 'true' === $_POST['refresh'];
   438→
   439→	// Get health data.
   440→	$health_data = adminpulse_get_health_data( $force_refresh );
   441→
   442→	if ( $health_data['error'] ) {
   443→		wp_send_json_error(
   444→			array( 'message' => __( "Couldn't check site health. Try refreshing.", 'adminpulse' ) )
   445→		);
   446→	}
   447→
   448→	// Generate HTML for the widget.
   449→	$html = adminpulse_generate_widget_html( $health_data );
   450→
   451→	wp_send_json_success(
   452→		array(
   453→			'html'        => $html,
   454→			'total_count' => $health_data['total_count'],
   455→		)
   456→	);
   457→}
   458→add_action( 'wp_ajax_adminpulse_get_health', 'adminpulse_ajax_get_health' );
   459→
   460→/**
   461→ * Generate HTML content for the widget.
   462→ *
   463→ * @param array $health_data The health data array.
   464→ * @return string HTML content.
   465→ */
   466→function adminpulse_generate_widget_html( $health_data ) {
   467→	ob_start();
   468→
   469→	if ( empty( $health_data['issues'] ) ) {
   470→		// Empty state: all healthy.
   471→		?>
   472→		<div class="adminpulse-healthy">
   473→			<span class="dashicons dashicons-yes-alt adminpulse-good"></span>
   474→			<p><?php esc_html_e( 'Everything looks good!', 'adminpulse' ); ?></p>
   475→		</div>
   476→		<?php
   477→	} else {
   478→		// Issue count summary with proper plural handling.
   479→		$count = $health_data['total_count'];
   480→		?>
   481→		<p class="adminpulse-summary">
   482→			<?php
   483→			printf(
   484→				/* translators: %d: number of issues */
   485→				esc_html( _n( '%d issue needs attention', '%d issues need attention', $count, 'adminpulse' ) ),
   486→				intval( $count )
   487→			);
   488→			?>
   489→		</p>
   490→		<ul class="adminpulse-issues-list">
   491→			<?php foreach ( $health_data['issues'] as $issue ) : ?>
   492→				<li class="adminpulse-issue <?php echo esc_attr( $issue['severity_class'] ); ?>">
   493→					<div class="adminpulse-issue-header">
   494→						<span class="adminpulse-badge <?php echo esc_attr( $issue['severity_class'] ); ?>">
   495→							<?php echo esc_html( $issue['severity_label'] ); ?>
   496→						</span>
   497→						<strong class="adminpulse-issue-label"><?php echo esc_html( $issue['label'] ); ?></strong>
   498→					</div>
   499→					<?php if ( ! empty( $issue['description'] ) ) : ?>
   500→						<p class="adminpulse-issue-description"><?php echo esc_html( $issue['description'] ); ?></p>
   501→					<?php endif; ?>
   502→					<?php if ( ! empty( $issue['actions'] ) ) : ?>
   503→						<div class="adminpulse-issue-actions">
   504→							<?php foreach ( $issue['actions'] as $action ) : ?>
   505→								<a href="<?php echo esc_url( $action['url'] ); ?>" class="adminpulse-action-link">
   506→									<?php echo esc_html( $action['label'] ); ?>
   507→								</a>
   508→							<?php endforeach; ?>
   509→						</div>
   510→					<?php endif; ?>
   511→				</li>
   512→			<?php endforeach; ?>
   513→		</ul>
   514→		<?php
   515→	}
   516→
   517→	return ob_get_clean();
   518→}
