    18→ */
    19→
    20→// Security check
    21→if ( ! defined( 'ABSPATH' ) ) {
    22→	exit;
    23→}
    24→
    25→// Define constants
    26→define( 'ADMINPULSE_VERSION', '1.0.0' );
    27→define( 'ADMINPULSE_DIR', plugin_dir_path( __FILE__ ) );
    28→define( 'ADMINPULSE_URL', plugin_dir_url( __FILE__ ) );
    29→
    30→/**
    31→ * Activation hook
    32→ */
    33→function adminpulse_activate() {
    34→	// Placeholder for activation logic
    35→}
    36→
    37→/**
    38→ * Deactivation hook
    39→ */
    40→function adminpulse_deactivate() {
    41→	// Clear cache on deactivation
    42→	adminpulse_clear_cache();
    43→}
    44→
    45→/**
    46→ * Bootstrap the plugin
    47→ */
    48→function adminpulse_boot() {
    49→	// Step 4: Hook to wp_dashboard_setup
    50→	add_action( 'wp_dashboard_setup', 'adminpulse_register_widget' );
    51→}
    52→
    53→/**
    54→ * Get cache key for health data
    55→ *
    56→ * Generates a cache key for storing health data. Includes blog ID for multisite isolation.
    57→ *
    58→ * @return string Cache key
    59→ */
    60→function adminpulse_get_cache_key() {
    61→	$key = 'adminpulse_health_data';
    62→
    63→	// Append blog ID for multisite isolation
    64→	if ( is_multisite() ) {
    65→		$key .= '_' . get_current_blog_id();
    66→	}
    67→
    68→	return $key;
