    71→/**
    72→ * Get cached health data with fallback
    73→ *
    74→ * Retrieves health data from cache. If cache miss, fetches fresh data and stores it.
    75→ *
    76→ * @return array Health data array or empty array on error
    77→ */
    78→function adminpulse_get_cached_health() {
    79→	$cache_key = adminpulse_get_cache_key();
    80→
    81→	// Try to get from cache
    82→	$cached_data = get_transient( $cache_key );
    83→
    84→	if ( false !== $cached_data ) {
    85→		return $cached_data;
    86→	}
    87→
    88→	// Cache miss - get fresh data
    89→	$data = adminpulse_get_health_issues();
    90→
    91→	// Store in cache for 1 hour
    92→	set_transient( $cache_key, $data, HOUR_IN_SECONDS );
    93→
    94→	return $data;
    95→}
