   223→/**
   224→ * Aggregates health issues from WP_Site_Health API
   225→ *
   226→ * Fetches health data from WordPress Site Health API, extracts relevant test results,
   227→ * and formats them for display. Handles API errors gracefully and filters to show only
   228→ * issues (not passing checks).
   229→ *
   230→ * @return array|WP_Error Array of health issues with standardized format, or WP_Error on failure
   231→ */
   232→function adminpulse_get_health_issues() {
   233→	// Step 2: Get WP_Site_Health instance
   234→	try {
   235→		$health = WP_Site_Health::get_instance();
   236→	} catch ( Exception $e ) {
   237→		// Step 3: Wrap API calls in try-catch for error handling
   238→		return new WP_Error(
   239→			'health_api_error',
   240→			'Failed to get WP_Site_Health instance',
   241→			array( 'details' => $e->getMessage() )
   242→		);
   243→	}
   244→
   245→	// Step 4: Get direct tests
   246→	try {
   247→		$tests = WP_Site_Health::get_tests();
   248→	} catch ( Exception $e ) {
   249→		return new WP_Error(
   250→			'health_tests_error',
   251→			'Failed to get health tests',
   252→			array( 'details' => $e->getMessage() )
   253→		);
   254→	}
   255→
   256→	// Ensure we have direct tests
   257→	if ( ! isset( $tests['direct'] ) || ! is_array( $tests['direct'] ) ) {
   258→		return array();
   259→	}
   260→
   261→	$health_issues = array();
   262→
   263→	// Run each direct test and collect results
   264→	foreach ( $tests['direct'] as $test ) {
   265→		try {
   266→			// Call the test function if it's callable
   267→			if ( is_callable( $test['test'] ) ) {
   268→				$result = call_user_func( $test['test'] );
   269→
   270→				// Step 5: Filter results to exclude 'good' status (show only issues)
   271→				if ( isset( $result['status'] ) && 'good' !== $result['status'] ) {
   272→					// Step 7: Map each result to standardized format
   273→					$mapped_result = array(
   274→						'label'       => isset( $result['label'] ) ? sanitize_text_field( $result['label'] ) : 'Unknown Test',
   275→						'status'      => isset( $result['status'] ) ? sanitize_text_field( $result['status'] ) : 'recommended',
   276→						'severity'    => adminpulse_get_severity( isset( $result['status'] ) ? $result['status'] : 'recommended' ),
   277→						'description' => isset( $result['description'] ) ? wp_kses_post( $result['description'] ) : '',
   278→						'actions'     => isset( $result['actions'] ) ? $result['actions'] : array(),
   279→					);
   280→
   281→					$health_issues[] = $mapped_result;
   282→				}
   283→			}
   284→		} catch ( Exception $e ) {
   285→			// Continue processing other tests even if one fails
   286→			continue;
   287→		}
   288→	}
   289→
   290→	// Step 6: Sort by severity: 'critical' first, then 'recommended'
   291→	usort(
   292→		$health_issues,
   293→		function ( $a, $b ) {
   294→			$severity_order = array( 'critical' => 0, 'recommended' => 1, 'good' => 2 );
   295→			$a_order        = $severity_order[ $a['status'] ] ?? 2;
   296→			$b_order        = $severity_order[ $b['status'] ] ?? 2;
   297→			return $a_order - $b_order;
   298→		}
   299→	);
   300→
   301→	// Step 8: Return array of issues
   302→	// Step 9: Handle empty results: return empty array (not error)
   303→	return $health_issues;
   304→}
