   483→/**
   484→ * AJAX endpoint to get health data as JSON
   485→ *
   486→ * Handles AJAX requests to fetch health data. Includes nonce verification,
   487→ * capability checks, and proper JSON responses. Supports both cache-hit
   488→ * fast path and refresh (cache-clear) mode.
   489→ *
   490→ * Step 1: Create adminpulse_ajax_get_health() function
   491→ * Step 2: Verify nonce
   492→ * Step 3: Check capability
   493→ * Step 4: Check for refresh flag
   494→ * Step 5: If refresh, clear cache first
   495→ * Step 6: Get health data
   496→ * Step 7: Check for WP_Error
   497→ * Step 8: Build response HTML
   498→ * Step 9: Return success
   499→ */
   500→function adminpulse_ajax_get_health() {
   501→	// Step 2: Verify nonce
   502→	check_ajax_referer( 'adminpulse_nonce', 'nonce' );
   503→
   504→	// Step 3: Check capability
   505→	if ( ! current_user_can( 'view_site_health' ) && ! current_user_can( 'manage_options' ) ) {
   506→		wp_send_json_error( __( 'Unauthorized', 'adminpulse' ), 403 );
   507→	}
   508→
   509→	// Step 4: Check for refresh flag
   510→	$refresh = isset( $_POST['refresh'] ) && $_POST['refresh'] === 'true'; // phpcs:ignore WordPress.Security.NonceVerification.Missing
   511→
   512→	// Step 5: If refresh, clear cache first
   513→	if ( $refresh ) {
   514→		adminpulse_clear_cache();
   515→	}
   516→
   517→	// Step 6: Get health data
   518→	$issues = adminpulse_get_cached_health();
   519→
   520→	// Step 7: Check for WP_Error
   521→	if ( is_wp_error( $issues ) ) {
   522→		wp_send_json_error( $issues->get_error_message() );
   523→	}
   524→
   525→	// Step 8: Build response HTML for each issue
   526→	$html = '';
   527→
   528→	foreach ( $issues as $issue ) {
   529→		$severity_class = adminpulse_get_severity_class( $issue['status'] );
   530→		$severity_label = adminpulse_get_severity_label( $issue['status'] );
   531→
   532→		// Build issue container with severity class
   533→		$html .= '<div class="adminpulse-issue ' . esc_attr( $severity_class ) . '">';
   534→
   535→		// Badge with severity label
   536→		$html .= '<span class="adminpulse-badge ' . esc_attr( 'adminpulse-badge-' . $issue['status'] ) . '">';
   537→		$html .= esc_html( $severity_label );
   538→		$html .= '</span>';
   539→
   540→		// Issue label
   541→		$html .= '<strong>';
   542→		$html .= esc_html( $issue['label'] );
   543→		$html .= '</strong>';
   544→
   545→		// Issue description
   546→		if ( ! empty( $issue['description'] ) ) {
   547→			$html .= '<p>';
   548→			$html .= wp_kses_post( $issue['description'] );
   549→			$html .= '</p>';
   550→		}
   551→
   552→		// Action links
   553→		if ( ! empty( $issue['actions'] ) ) {
   554→			$html .= '<div class="adminpulse-actions">';
   555→			foreach ( $issue['actions'] as $action ) {
   556→				if ( isset( $action['label'] ) && isset( $action['url'] ) ) {
   557→					$html .= '<a href="' . esc_url( $action['url'] ) . '" class="adminpulse-action-link" target="_blank" rel="noopener noreferrer">';
   558→					$html .= esc_html( $action['label'] );
   559→					$html .= '</a> ';
   560→				}
   561→			}
   562→			$html .= '</div>';
   563→		}
   564→
   565→		$html .= '</div>';
   566→	}
   567→
   568→	// Step 9: Return success with HTML and count
   569→	wp_send_json_success(
   570→		array(
   571→			'html'  => $html,
   572→			'count' => count( $issues ),
   573→		)
   574→	);
   575→}
