    11→	public static function classify( $message ) {
    12→		$api_key = relay_decrypt_api_key();
    13→		if ( empty( $api_key ) ) {
    14→			return null;
    15→		}
    16→
    17→		$prompt = self::build_prompt( $message );
    18→
    19→		$body = wp_json_encode( array(
    20→			'model'       => 'claude-3-haiku-20240307',
    21→			'max_tokens'  => 256,
    22→			'messages'    => array(
    23→				array(
    24→					'role'    => 'user',
    25→					'content' => $prompt,
    26→				),
    27→			),
    28→		) );
    29→
    30→		$args = array(
    31→			'method'  => 'POST',
    32→			'timeout' => 30,
    33→			'headers' => array(
    34→				'Content-Type'  => 'application/json',
    35→				'x-api-key'     => $api_key,
    36→				'anthropic-version' => '2023-06-01',
    37→			),
    38→			'body'    => $body,
    39→		);
    40→
    41→		$attempt = 0;
    42→		$response = null;
    43→
    44→		while ( $attempt < self::MAX_RETRIES ) {
    45→			$response = wp_remote_post( self::API_URL, $args );
    46→
    47→			if ( ! is_wp_error( $response ) ) {
    48→				$status = wp_remote_retrieve_response_code( $response );
    49→				if ( 200 === $status ) {
    50→					break;
    51→				}
    52→			}
    53→
    54→			$attempt++;
    55→			if ( $attempt < self::MAX_RETRIES ) {
    56→				$backoff = (int) pow( 2, $attempt );
    57→				sleep( $backoff );
    58→			}
    59→		}
    60→
    61→		if ( is_wp_error( $response ) ) {
    62→			return null;
    63→		}
    64→
    65→		$status = wp_remote_retrieve_response_code( $response );
    66→		if ( 200 !== $status ) {
    67→			return null;
    68→		}
    69→
    70→		$body = wp_remote_retrieve_body( $response );
    71→		$data = json_decode( $body, true );
    72→
    73→		if ( empty( $data['content'] ) || ! is_array( $data['content'] ) ) {
    74→			return null;
    75→		}
    76→
    77→		$text = '';
    78→		foreach ( $data['content'] as $block ) {
    79→			if ( isset( $block['text'] ) ) {
    80→				$text .= $block['text'];
    81→			}
    82→		}
    83→
    84→		$json = self::extract_json( $text );
    85→		if ( empty( $json ) ) {
    86→			return null;
    87→		}
    88→
    89→		$parsed = json_decode( $json, true );
    90→		if ( ! is_array( $parsed ) ) {
    91→			return null;
    92→		}
    93→
    94→		$required = array( 'category', 'urgency', 'reason' );
    95→		foreach ( $required as $key ) {
    96→			if ( ! isset( $parsed[ $key ] ) ) {
    97→				return null;
    98→			}
    99→		}
   100→
   101→		$parsed['category'] = sanitize_text_field( $parsed['category'] );
   102→		$parsed['urgency']  = sanitize_text_field( $parsed['urgency'] );
   103→		$parsed['reason']   = sanitize_text_field( $parsed['reason'] );
   104→
   105→		$valid_categories = array( 'Sales', 'Support', 'Spam', 'General' );
   106→		$valid_urgencies  = array( 'High', 'Medium', 'Low' );
   107→
   108→		if ( ! in_array( $parsed['category'], $valid_categories, true ) ) {
   109→			$parsed['category'] = 'General';
   110→		}
   111→		if ( ! in_array( $parsed['urgency'], $valid_urgencies, true ) ) {
   112→			$parsed['urgency'] = 'Medium';
   113→		}
   114→
   115→		return $parsed;
   116→	}
