   118→	private static function build_prompt( $message ) {
   119→		return "Classify the following form submission. Respond with ONLY a JSON object containing exactly these keys: category, urgency, reason.\n"
   120→			. "category must be one of: Sales, Support, Spam, General.\n"
   121→			. "urgency must be one of: High, Medium, Low.\n\n"
   122→			. "Form submission:\n" . $message . "\n\n"
   123→			. "JSON response:";
   124→	}
   125→
   126→	private static function extract_json( $text ) {
   127→		$text = trim( $text );
   128→		$start = strpos( $text, '{' );
   129→		$end   = strrpos( $text, '}' );
   130→
   131→		if ( false === $start || false === $end || $end < $start ) {
   132→			return null;
   133→		}
   134→
   135→		return substr( $text, $start, $end - $start + 1 );
   136→	}
   137→}
