    15→class Scribe_API {
    16→
    17→	/**
    18→	 * Max file size in bytes (50 MB).
    19→	 *
    20→	 * @var int
    21→	 */
    22→	const MAX_FILE_SIZE = 52428800;
    23→
    24→	/**
    25→	 * Max retries for API calls.
    26→	 *
