    29→	const MAX_RETRIES = 3;
    30→
    31→	/**
    32→	 * Get the OpenAI API key.
    33→	 *
    34→	 * @return string
    35→	 */
    36→	public static function get_api_key() {
    37→		if ( defined( 'SCRIBE_API_KEY' ) ) {
    38→			return SCRIBE_API_KEY;
    39→		}
    40→
    41→		$encrypted = get_option( 'scribe_api_key', '' );
    42→		if ( empty( $encrypted ) ) {
    43→			return '';
    44→		}
    45→
    46→		$key = openssl_decrypt( base64_decode( $encrypted ), 'AES-128-ECB', self::get_encryption_key() );
    47→		return $key ? $key : '';
    48→	}
    49→
    50→	/**
    51→	 * Get the encryption key.
    52→	 *
    53→	 * @return string
    54→	 */
    55→	private static function get_encryption_key() {
    56→		$key = defined( 'LOGGED_IN_KEY' ) ? LOGGED_IN_KEY : 'scribe-default-key';
    57→		return substr( hash( 'sha256', $key ), 0, 16 );
    58→	}
    59→
    60→	/**
    61→	 * Transcribe an audio file via Whisper.
    62→	 *
    63→	 * @param string $file_path Absolute path to the audio file.
    64→	 * @return array|
    65→	 */
    66→	public static function transcribe( $file_path ) {
    67→		if ( ! file_exists( $file_path ) ) {
    68→			return new WP_Error( 'file_not_found', __( 'Audio file not found.', 'scribe' ) );
    69→		}
    70→
    71→		$file_size = filesize( $file_path );
    72→		if ( $file_size > self::MAX_FILE_SIZE ) {
    73→			return new WP_Error( 'file_too_large', __( 'File exceeds 50 MB limit.', 'scribe' ) );
    74→		}
    75→
    76→		$api_key = self::get_api_key();
    77→		if ( empty( $api_key ) ) {
    78→			return new WP_Error( 'missing_key', __( 'OpenAI API key is not configured.', 'scribe' ) );
    79→		}
    80→
    81→		$mime_type = wp_check_filetype( basename( $file_path ) );
    82→		$mime      = ! empty( $mime_type['type'] ) ? $mime_type['type'] : 'audio/mpeg';
    83→
    84→		$boundary = wp_generate_password( 24, false );
    85→		$payload  = '--' . $boundary . "\r\n";
    86→		$payload .= 'Content-Disposition: form-data; name="model"' . "\r\n\r\n";
    87→		$payload .= 'whisper-1' . "\r\n";
    88→		$payload .= '--' . $boundary . "\r\n";
    89→		$payload .= 'Content-Disposition: form-data; name="response_format"' . "\r\n\r\n";
    90→		$payload .= 'verbose_json' . "\r\n";
    91→		$payload .= '--' . $boundary . "\r\n";
    92→		$payload .= 'Content-Disposition: form-data; name="file"; filename="' . basename( $file_path ) . '"' . "\r\n";
    93→		$payload .= 'Content-Type: ' . $mime . "\r\n\r\n";
    94→		$payload .= file_get_contents( $file_path ) . "\r\n";
    95→		$payload .= '--' . $boundary . '--';
    96→
    97→		$headers = array(
    98→			'Authorization' => 'Bearer ' . $api_key,
    99→			'Content-Type'  => 'multipart/form-data; boundary=' . $boundary,
   100→		);
   101→
   102→		$attempt = 0;
   103→		$backoff = 1;
   104→
   105→		while ( $attempt < self::MAX_RETRIES ) {
   106→			$response = wp_remote_post(
   107→				'https://api.openai.com/v1/audio/transcriptions',
   108→				array(
   109→					'headers' => $headers,
   110→					'body'    => $payload,
   111→					'timeout' => 120,
   112→				)
   113→			);
   114→
   115→			$attempt++;
   116→
   117→			if ( is_wp_error( $response ) ) {
   118→				if ( $attempt >= self::MAX_RETRIES ) {
   119→					return new WP_Error( 'request_failed', __( 'Could not reach OpenAI. Please try again.', 'scribe' ) );
   120→				}
   121→				sleep( $backoff );
   122→				$backoff *= 2;
   123→				continue;
   124→			}
   125→
   126→			$status_code = wp_remote_retrieve_response_code( $response );
   127→			$body        = wp_remote_retrieve_body( $response );
   128→
   129→			if ( 200 === $status_code ) {
   130→				$data = json_decode( $body, true );
   131→				if ( json_last_error() !== JSON_ERROR_NONE ) {
   132→					return new WP_Error( 'invalid_json', __( 'Invalid response from OpenAI.', 'scribe' ) );
   133→				}
   134→				return $data;
   135→			}
   136→
   137→			if ( $status_code >= 400 && $status_code < 500 ) {
   138→				$message = __( 'Transcription failed. Please check your API key or file format.', 'scribe' );
   139→				if ( 429 === $status_code ) {
   140→					$message = __( 'Rate limit exceeded. Please try again later.', 'scribe' );
   141→				}
   142→				return new WP_Error( 'api_error', $message, array( 'status' => $status_code ) );
   143→			}
   144→
   145→			if ( $status_code >= 500 ) {
   146→				if ( $attempt >= self::MAX_RETRIES ) {
   147→					return new WP_Error( 'server_error', __( 'OpenAI server error. Please try again later.', 'scribe' ) );
   148→				}
   149→				sleep( $backoff );
   150→				$backoff *= 2;
   151→				continue;
   152→			}
   153→		}
   154→
   155→		return new WP_Error( 'unknown_error', __( 'An unexpected error occurred.', 'scribe' ) );
   156→	}
   157→}
