     1→/**
     2→ * Claude Parser
     3→ *
     4→ * Parses Claude conversation export JSON into structured Portfolio objects.
     5→ * Wrapped in try/catch with graceful error handling for schema drift.
     6→ */
     7→
     8→import type {
     9→  ClaudeExport,
