    16→
    17→/**
    18→ * Generates a UUID v4
    19→ */
    20→function generateUUID(): string {
    21→  if (typeof crypto !== 'undefined' && 'randomUUID' in crypto) {
    22→    return crypto.randomUUID();
    23→  }
    24→  // Fallback for environments without crypto.randomUUID
    25→  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    26→    const r = (Math.random() * 16) | 0;
    27→    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    28→    return v.toString(16);
    29→  });
    30→}
    31→
    32→/**
    33→ * Extracts a title from prompt content
    34→ * Takes first ~60 characters or first line, whichever is shorter
    35→ */
    36→function extractTitle(content: string): string {
