     1→<?php
     2→/**
     3→ * Class Relay_Server
     4→ *
     5→ * Registers REST routes for SSE and messages.
     6→ * Handles SSE stream with session management and rate limiting.
     7→ */
     8→class Relay_Server {
     9→
    10→	/**
    11→	 * @var Relay_Tool_Registry
    12→	 */
    13→	private $registry;
    14→
    15→	/**
    16→	 * @var Relay_Auth
    17→	 */
    18→	private $auth;
    19→
    20→	/**
    21→	 * Constructor.
    22→	 */
    23→	public function __construct() {
    24→		$this->auth = new Relay_Auth();
    25→	}
    26→
    27→	/**
    28→	 * Set the tool registry.
    29→	 *
    30→	 * @param Relay_Tool_Registry $registry Tool registry instance.
    31→	 */
    32→	public function set_registry( Relay_Tool_Registry $registry ) {
    33→		$this->registry = $registry;
    34→	}
    35→
    36→	/**
    37→	 * Register REST routes.
    38→	 */
    39→	public function register_routes() {
    40→		register_rest_route(
    41→			'agentbridge/v1',
    42→			'/sse',
    43→			array(
    44→				'methods'             => 'GET',
    45→				'callback'            => array( $this, 'handle_sse' ),
    46→				'permission_callback' => '__return_true',
    47→			)
    48→		);
    49→
    50→		register_rest_route(
    51→			'agentbridge/v1',
    52→			'/messages',
    53→			array(
    54→				'methods'             => 'POST',
    55→				'callback'            => array( $this, 'handle_message' ),
    56→				'permission_callback' => array( $this, 'check_permission' ),
    57→			)
    58→		);
    59→	}
    60→
    61→	/**
    62→	 * Check permission for message endpoint.
    63→	 *
    64→	 * @param WP_REST_Request $request Full data about the request.
    65→	 * @return true|WP_Error
    66→	 */
    67→	public function check_permission( $request ) {
    68→		$auth_header = $request->get_header( 'authorization' );
    69→		if ( ! $auth_header || ! $this->auth->validate_token( $auth_header ) ) {
    70→			return new WP_Error(
    71→				'rest_forbidden',
    72→				__( 'Invalid or missing bearer token.', 'agentbridge' ),
    73→				array( 'status' => 401 )
    74→			);
    75→		}
    76→
    77→		if ( ! current_user_can( 'edit_posts' ) ) {
    78→			return new WP_Error(
    79→				'rest_forbidden',
    80→				__( 'You do not have permission to use AgentBridge.', 'agentbridge' ),
    81→				array( 'status' => 403 )
    82→			);
    83→		}
    84→
    85→		return true;
    86→	}
    87→
    88→	/**
    89→	 * Handle SSE endpoint.
    90→	 *
    91→	 * @param WP_REST_Request $request Full data about the request.
    92→	 */
    93→	public function handle_sse( $request ) {
    94→		// Rate limiting: max 10 connections per IP per 60 seconds
    95→		$ip          = isset( $_SERVER['REMOTE_ADDR'] ) ? sanitize_text_field( wp_unslash( $_SERVER['REMOTE_ADDR'] ) ) : '';
    96→		$rate_key    = 'agentbridge_rate_' . md5( $ip );
    97→		$rate_count  = (int) get_transient( $rate_key );
    98→		$max_connections = 10;
    99→		$window      = 60;
   100→
   101→		if ( $rate_count >= $max_connections ) {
   102→			status_header( 429 );
   103→			echo 'event: error\ndata: ' . wp_json_encode( array( 'error' => 'Rate limit exceeded. Try again later.' ) ) . "\n\n";
   104→			exit;
   105→		}
   106→
   107→		set_transient( $rate_key, $rate_count + 1, $window );
   108→
   109→		// Generate session ID
   110→		$session_id = wp_generate_password( 32, false );
   111→		set_transient( 'agentbridge_session_' . $session_id, array(), 300 );
   112→
   113→		// Send SSE headers
   114→		header( 'Content-Type: text/event-stream' );
   115→		header( 'Cache-Control: no-cache' );
   116→		header( 'Connection: keep-alive' );
   117→
   118→		// Send initial endpoint event
   119→		$this->send_event( $session_id, 'endpoint', array( 'session_id' => $session_id ) );
   120→
   121→		// Keep connection alive
   122→		$start_time = time();
   123→		$max_lifetime = 300; // 5 minutes
   124→
   125→		while ( true ) {
   126→			if ( connection_aborted() || ( time() - $start_time ) > $max_lifetime ) {
   127→				break;
   128→			}
   129→
   130→			// Check for messages in transient
   131→			$messages = get_transient( 'agentbridge_messages_' . $session_id );
   132→			if ( ! empty( $messages ) && is_array( $messages ) ) {
   133→				foreach ( $messages as $message ) {
   134→					$this->send_event( $session_id, 'message', $message );
   135→				}
   136→				delete_transient( 'agentbridge_messages_' . $session_id );
   137→			}
   138→
   139→			sleep( 1 );
   140→			ob_flush();
   141→			flush();
   142→		}
   143→
   144→		// Clean up session
   145→		delete_transient( 'agentbridge_session_' . $session_id );
   146→		exit;
   147→	}
   148→
   149→	/**
   150→	 * Send an SSE event.
   151→	 *
   152→	 * @param string $session_id Session ID.
   153→	 * @param string $event     Event name.
   154→	 * @param mixed  $data      Event data.
   155→	 */
   156→	private function send_event( $session_id, $event, $data ) {
   157→		echo 'event: ' . esc_attr( $event ) . "\n";
   158→		echo 'data: ' . wp_json_encode( $data ) . "\n\n";
   159→		ob_flush();
   160→		flush();
   161→	}
   162→
   163→	/**
   164→	 * Queue a message for a session.
   165→	 *
   166→	 * @param string $session_id Session ID.
   167→	 * @param mixed  $data      Message data.
   168→	 * @return bool
   169→	 */
   170→	public function queue_message( $session_id, $data ) {
   171→		$messages = get_transient( 'agentbridge_messages_' . $session_id );
   172→		if ( ! is_array( $messages ) ) {
   173→			$messages = array();
   174→		}
   175→		$messages[] = $data;
   176→		return set_transient( 'agentbridge_messages_' . $session_id, $messages, 300 );
   177→	}
   178→
   179→	/**
   180→	 * Handle incoming JSON-RPC message.
   181→	 *
   182→	 * @param WP_REST_Request $request Full data about the request.
   183→	 * @return WP_REST_Response
   184→	 */
   185→	public function handle_message( $request ) {
   186→		$session_id = $request->get_param( 'session_id' );
   187→		if ( empty( $session_id ) ) {
   188→			return new WP_REST_Response(
   189→				array(
   190→					'jsonrpc' => '2.0',
   191→					'error'   => array(
   192→						'code'    => -32600,
   193→						'message' => 'Invalid Request: missing session_id',
   194→					),
   195→					'id'      => null,
   196→				),
   197→				400
   198→			);
   199→		}
   200→
   201→		$body = $request->get_body();
   202→		$data = json_decode( $body, true );
   203→
   204→		if ( null === $data || ! isset( $data['jsonrpc'] ) || '2.0' !== $data['jsonrpc'] ) {
   205→			return new WP_REST_Response(
   206→				array(
   207→					'jsonrpc' => '2.0',
   208→					'error'   => array(
   209→						'code'    => -32600,
   210→						'message' => 'Invalid Request',
   211→					),
   212→					'id'      => isset( $data['id'] ) ? $data['id'] : null,
   213→				),
   214→				400
   215→			);
   216→		}
   217→
   218→		$handler = new Relay_Message_Handler( $this->registry, $this );
   219→		$response = $handler->handle( $data );
   220→
   221→		return new WP_REST_Response( $response, 200 );
   222→	}
   223→
   224→	/**
   225→	 * Add CORS headers to REST responses.
   226→	 *
   227→	 * @param mixed $value Response value.
   228→	 * @return mixed
   229→	 */
   230→	public function add_cors_headers( $value ) {
   231→		$origins = apply_filters( 'relay_cors_origins', '*' );
   232→		if ( is_array( $origins ) ) {
   233→			$origin = isset( $_SERVER['HTTP_ORIGIN'] ) ? sanitize_text_field( wp_unslash( $_SERVER['HTTP_ORIGIN'] ) ) : '*';
   234→			if ( in_array( $origin, $origins, true ) ) {
   235→				header( 'Access-Control-Allow-Origin: ' . esc_url_raw( $origin ) );
   236→			}
   237→		} else {
   238→			header( 'Access-Control-Allow-Origin: ' . esc_attr( $origins ) );
   239→		}
   240→		return $value;
   241→	}
   242→}
   243→
   244→// Add CORS headers filter
   245→add_filter( 'rest_pre_serve_request', array( new Relay_Server(), 'add_cors_headers' ) );
